  <text x="20" y="48" fill="#a1a1aa" font-family="sans-serif" font-size="13">100~1,000BTCウォレットが6万7,000BTC出庫、取引所3社合計7,660BTC受領</text>
  <text x="20" y="100" fill="#d4d4d8" font-family="sans-serif" font-size="14" font-weight="700">100-1K BTC 出庫</text>
  <rect x="230" y="86" width="420" height="28" rx="4" fill="#f59e0b"/>
  <text x="662" y="106" text-anchor="end" fill="#f59e0b" font-family="sans-serif" font-size="14" font-weight="700">67,000</text>
  <text x="20" y="170" fill="#d4d4d8" font-family="sans-serif" font-size="14" font-weight="700">バイナンス</text>
  <rect x="230" y="156" width="18" height="28" rx="3" fill="#38bdf8"/>
  <text x="256" y="176" fill="#38bdf8" font-family="sans-serif" font-size="14" font-weight="700">2,800</text>
  <text x="20" y="230" fill="#d4d4d8" font-family="sans-serif" font-size="14" font-weight="700">コインベース・プライム</text>
  <rect x="230" y="216" width="11" height="28" rx="3" fill="#38bdf8"/>
  <text x="249" y="236" fill="#38bdf8" font-family="sans-serif" font-size="14" font-weight="700">1,690</text>
  <text x="20" y="290" fill="#d4d4d8" font-family="sans-serif" font-size="14" font-weight="700">コインベース・アドバンスト</text>
